my $text = Mojo::File->new('/Users/daboe01/src/HPO/hp.obo')->slurp;

my @terms = split /\[Term\]/, $text;
shift @terms; # cut header off

# Print the TSV Header to STDOUT
print join("\t", "Term_ID", "Synonym", "Is_Modifier", "Is_Eye"), "\n";

foreach my $term (@terms) {
    # Use ^ and /m to ensure we only match at the start of a line
    my ($id) = $term =~ /^id:\s*(HP:.+)/m;
    next unless defined $id; # Skip safely if it's a malformed block
    # Extract the main term name
    my ($name) = $term =~ /^name:\s*(.+)/m;

    # Determine if it is a modifier (1 for yes, 0 for no)
    my $is_mod = exists $modifiers{$id} ? 1 : 0;
    my $is_eye = exists $eye{$id} ? 1 : 0;
next unless $is_mod;

    $id = $1 if $id =~/HP:(.+)/io;
    $id = $id + 0;

    # Add the main term to the list
    # print join("\t", $id, $name, $is_mod, $is_eye), "\n" if defined $name;
    print join(";", $id, $name), "\n" if defined $name;

    # Extract all Synonyms and print them out row by row
    while ($term =~ /^synonym:\s*"([^"]+)"/mg) {
            my $synonym = $1;
        print join(";", $id, $synonym), "\n";
        #print join("\t", $id, $synonym, $is_mod, $is_eye), "\n";
    }
}
